INSERT INTO questions (difficulty, question_text, options, correct_answer_old, correct_index, explanation) VALUES
('elementary', 'My parents ___ teachers.', '["A. am", "B. is", "C. are", "D. be"]'::jsonb, 'C', 2, '複數主詞 parents 用 are。'),
('elementary', 'Grandpa ___ reading every morning.', '["A. am", "B. is", "C. are", "D. be"]'::jsonb, 'B', 1, '第三人稱單數用 is。'),
('elementary', '___ there any milk left?', '["A. Is", "B. Are", "C. Am", "D. Do"]'::jsonb, 'A', 0, '不可數 milk 與 there be 搭配用 Is there。'),
('elementary', '___ those your stickers?', '["A. Is", "B. Are", "C. Am", "D. Was"]'::jsonb, 'B', 1, 'those 複數用 Are。'),
('elementary', 'I ___ not hungry.', '["A. am", "B. is", "C. are", "D. be"]'::jsonb, 'A', 0, 'I 配 am。'),
('elementary', 'We ___ from Canada.', '["A. am", "B. is", "C. are", "D. be"]'::jsonb, 'C', 2, 'We 複數用 are。'),
('elementary', '___ does the shop open?', '["A. When", "B. Who", "C. Whose", "D. Which"]'::jsonb, 'A', 0, '問時間用 When。'),
('elementary', '___ bag are you carrying?', '["A. Who", "B. Which", "C. Whose", "D. Where"]'::jsonb, 'B', 1, '問哪一個／款式用 Which。'),
('elementary', 'Every weekend she ___ her grandma.', '["A. visit", "B. visits", "C. visiting", "D. visited"]'::jsonb, 'B', 1, '習慣動作 she + visit + s。'),
('elementary', 'They ___ football now.', '["A. play", "B. plays", "C. are playing", "D. played"]'::jsonb, 'C', 2, 'now 表現在進行。'),
('elementary', 'Look! It ___ .', '["A. rain", "B. rains", "C. is raining", "D. rained"]'::jsonb, 'C', 2, 'Look 提示正在發生。'),
('elementary', 'I ___ never ___ sushi.', '["A. have / eat", "B. have / eaten", "C. has / eaten", "D. had / eat"]'::jsonb, 'B', 1, '現在完成式 have eaten。'),
('elementary', 'She ___ to Tokyo twice.', '["A. go", "B. goes", "C. has gone", "D. went"]'::jsonb, 'C', 2, '經驗次數用現在完成式。'),
('elementary', 'Before bed I always ___ my teeth.', '["A. brush", "B. brushes", "C. brushing", "D. brushed"]'::jsonb, 'A', 0, 'I + always + 現在式 brush。'),
('elementary', 'Can we ___ outside?', '["A. plays", "B. play", "C. playing", "D. played"]'::jsonb, 'B', 1, 'can 後接原形。'),
('elementary', 'She ___ play the piano when she was six.', '["A. can", "B. could", "C. may", "D. must"]'::jsonb, 'B', 1, '過去能力用 could。'),
('elementary', 'You ___ wear a helmet on this ride.', '["A. should", "B. shouldn''t", "C. might", "D. could"]'::jsonb, 'A', 0, '安全規定建議 should。'),
('elementary', 'It''s dark. You ___ leave alone.', '["A. should", "B. shouldn''t", "C. must", "D. might"]'::jsonb, 'B', 1, '危險情境建議不要.shouldn''t。'),
('elementary', 'There ___ many kinds of juice in the jug.', '["A. is", "B. are", "C. be", "D. am"]'::jsonb, 'B', 1, 'kinds 為可數複數，用 there are。'),
('elementary', 'How ___ students are in the club?', '["A. much", "B. many", "C. long", "D. often"]'::jsonb, 'B', 1, '可數名詞數量用 How many。'),
('elementary', 'How ___ does the ticket cost?', '["A. many", "B. much", "C. often", "D. far"]'::jsonb, 'B', 1, '價錢用 How much。'),
('elementary', 'I''d like ___ water, please.', '["A. any", "B. some", "C. many", "D. few"]'::jsonb, 'B', 1, '肯定請求液體用 some。'),
('elementary', 'We don''t have ___ eggs.', '["A. some", "B. any", "C. much", "D. many"]'::jsonb, 'B', 1, '否定句「任何」用 any。'),
('elementary', 'That is ___ elephant.', '["A. a", "B. an", "C. the", "D. no article"]'::jsonb, 'B', 1, 'elephant 母音開頭用 an。'),
('elementary', 'Pass me ___ salt.', '["A. a", "B. an", "C. the", "D. no article"]'::jsonb, 'C', 2, '特指桌上的鹽用 the。'),
('elementary', '___ Earth goes around the Sun.', '["A. A", "B. An", "C. The", "D. no article"]'::jsonb, 'C', 2, '獨一無二事物用 the。'),
('elementary', 'I''ve lost ___ pen you lent me.', '["A. a", "B. an", "C. the", "D. no article"]'::jsonb, 'C', 2, '特定那支筆用 the。'),
('elementary', 'She runs ___ than her brother.', '["A. fast", "B. faster", "C. fastest", "D. more fast"]'::jsonb, 'B', 1, '兩者比較用比較級 faster。'),
('elementary', 'This is the ___ pizza I''ve ever had.', '["A. good", "B. better", "C. best", "D. more good"]'::jsonb, 'C', 2, 'ever 搭配最高級 best。'),
('elementary', 'My room is ___ than yours.', '["A. big", "B. bigger", "C. biggest", "D. more big"]'::jsonb, 'B', 1, 'than 用比較級 bigger。'),
('elementary', 'She speaks English ___ .', '["A. good", "B. well", "C. better", "D. best"]'::jsonb, 'B', 1, '修飾動詞 speak 用副詞 well。'),
('elementary', '___ carefully, please!', '["A. Listen", "B. Listen to", "C. Hear", "D. Sound"]'::jsonb, 'A', 0, '祈使「聽」用 Listen（不及物）。'),
('elementary', '___ you help me carry this?', '["A. Can", "B. Should", "C. Must", "D. May"]'::jsonb, 'A', 0, '請求協助常用 Can。'),
('elementary', 'I''m interested ___ science fiction.', '["A. on", "B. in", "C. at", "D. for"]'::jsonb, 'B', 1, 'be interested in。'),
('elementary', 'Good ___! You''ll do better next time.', '["A. luck", "B. luckily", "C. lucky", "D. unlucky"]'::jsonb, 'A', 0, '安慰常用 Good luck 或加油語境。'),
('elementary', 'See you ___ weekend!', '["A. this", "B. at this", "C. on this", "D. the"]'::jsonb, 'A', 0, 'this weekend 固定說法。'),
('elementary', '___ happy birthday!', '["A. Say", "B. Wish", "C. Tell", "D. Speak"]'::jsonb, 'B', 1, '祝賀生日常用 Wish。'),
('elementary', 'Turn ___ the TV; it''s too loud.', '["A. on", "B. off", "C. up", "D. in"]'::jsonb, 'B', 1, '太吵要關掉用 turn off。'),
('elementary', '___ up early makes me tired.', '["A. Wake", "B. Waking", "C. Woke", "D. Wakes"]'::jsonb, 'B', 1, '主詞用動名詞 Waking。'),
('elementary', 'I''d like ___ pizza slice.', '["A. other", "B. another", "C. others", "D. the other"]'::jsonb, 'B', 1, '再一片（不定數中再一個）用 another。'),
('elementary', 'Both answers ___ wrong.', '["A. is", "B. are", "C. am", "D. was"]'::jsonb, 'B', 1, 'Both + 複數名詞用 are。'),
('elementary', 'Neither answer ___ correct.', '["A. are", "B. is", "C. were", "D. be"]'::jsonb, 'B', 1, 'Neither + 單數名詞視為單數 is。'),
('elementary', 'Put your toys ___ the box.', '["A. at", "B. on", "C. in", "D. to"]'::jsonb, 'C', 2, '放入盒子內部用 in。'),
('elementary', 'The poster is ___ the wall.', '["A. in", "B. on", "C. at", "D. over"]'::jsonb, 'B', 1, '貼在牆面上用 on。'),
('elementary', 'We''ll meet ___ noon.', '["A. on", "B. in", "C. at", "D. by"]'::jsonb, 'C', 2, '時刻 at noon。'),
('elementary', '___ spring, flowers bloom.', '["A. On", "B. At", "C. In", "D. By"]'::jsonb, 'C', 2, '季節用 in。'),
('elementary', 'We''re traveling ___ plane.', '["A. by", "B. on", "C. with", "D. in"]'::jsonb, 'A', 0, '交通工具 by plane。'),
('elementary', 'I''m afraid ___ spiders.', '["A. for", "B. of", "C. about", "D. with"]'::jsonb, 'B', 1, 'be afraid of。'),
('elementary', 'Could you speak ___ slowly?', '["A. more", "B. many", "C. much", "D. most"]'::jsonb, 'A', 0, '請對方「再慢一點」用 more slowly。'),
('elementary', 'This puzzle is easy ___ me.', '["A. for", "B. to", "C. with", "D. of"]'::jsonb, 'A', 0, '對某人而言簡單用 for。'),
('elementary', 'What''s the opposite of ''cheap''?', '["A. small", "B. expensive", "C. short", "D. cold"]'::jsonb, 'B', 1, 'cheap 的反義常用 expensive。'),
('elementary', 'Which month comes ___ October?', '["A. before", "B. after", "C. between", "D. during"]'::jsonb, 'B', 1, '十一月接在十月之後。'),
('elementary', 'A rectangle has ___ sides.', '["A. three", "B. four", "C. five", "D. six"]'::jsonb, 'B', 1, '長方形四邊。'),
('elementary', 'Water freezes at ___ Celsius.', '["A. 0", "B. 32", "C. 100", "D. 50"]'::jsonb, 'A', 0, '水的冰點攝氏 0 度。'),
('elementary', 'Which animal lives in water and jumps?', '["A. lion", "B. frog", "C. cow", "D. eagle"]'::jsonb, 'B', 1, '青蛙典型在水邊／水中活動並跳躍。'),
('elementary', 'You cut vegetables with a ___.', '["A. ball", "B. knife", "C. hat", "D. pillow"]'::jsonb, 'B', 1, '用刀切菜。'),
('elementary', 'We listen to music with our ___.', '["A. eyes", "B. ears", "C. nose", "D. hands"]'::jsonb, 'B', 1, '耳朵聽音樂。'),
('elementary', 'What do you use to tell time?', '["A. a map", "B. a clock", "C. a spoon", "D. a pillow"]'::jsonb, 'B', 1, '時鐘看時間。'),
('elementary', 'If you are hungry, you want ___.', '["A. sleep", "B. food", "C. ice", "D. darkness"]'::jsonb, 'B', 1, '餓了想吃東西。'),
('elementary', 'This juice tastes ___.', '["A. sweetly", "B. sweet", "C. sweetness", "D. sweeter"]'::jsonb, 'B', 1, '感官動詞 taste 後接形容詞 sweet。'),
('elementary', 'The baby seems ___.', '["A. happily", "B. happy", "C. happiness", "D. more happy"]'::jsonb, 'B', 1, 'seem + 形容詞。'),
('elementary', '___ one is yours — the red or the blue?', '["A. When", "B. Which", "C. What", "D. Who"]'::jsonb, 'B', 1, '在有限選擇中問哪一個用 Which。'),
('elementary', '___ father is a pilot?', '["A. Who", "B. Whose", "C. Which", "D. What"]'::jsonb, 'B', 1, '問「誰的父親」用 Whose。'),
('elementary', 'Please ___ quiet in the hospital.', '["A. are", "B. be", "C. is", "D. being"]'::jsonb, 'B', 1, '祈使句用 Be quiet。'),
('elementary', 'Let''s ___ the homework together.', '["A. do", "B. does", "C. doing", "D. did"]'::jsonb, 'A', 0, 'Let''s + 原形。'),
('elementary', 'Don''t ___ your phone in class.', '["A. uses", "B. use", "C. using", "D. used"]'::jsonb, 'B', 1, 'Don''t + 原形。'),
('elementary', 'She forgot ___ her umbrella.', '["A. bring", "B. to bring", "C. bringing", "D. brought"]'::jsonb, 'B', 1, 'forget to + 原形表忘了去做。'),
('elementary', 'Remember ___ the door.', '["A. lock", "B. to lock", "C. locking", "D. locked"]'::jsonb, 'B', 1, 'remember to lock 記得要鎖。'),
('elementary', 'He wants ___ a pilot.', '["A. be", "B. to be", "C. being", "D. been"]'::jsonb, 'B', 1, 'want to be。'),
('elementary', 'I''m learning ___ swim.', '["A. for", "B. to", "C. how to", "D. how"]'::jsonb, 'C', 2, '學習如何游泳用 how to swim。'),
('elementary', 'It''s important ___ sleep enough.', '["A. for", "B. to", "C. that", "D. of"]'::jsonb, 'B', 1, 'It''s important to + 原形。'),
('elementary', 'Could you tell me the ___ ?', '["A. true", "B. truth", "C. truly", "D. truths"]'::jsonb, 'B', 1, 'tell the truth 說實話。'),
('elementary', 'There were ___ people at the park.', '["A. much", "B. many", "C. a little", "D. little"]'::jsonb, 'B', 1, '可數 people 用 many。'),
('elementary', 'How ___ homework do you have?', '["A. many", "B. much", "C. often", "D. long"]'::jsonb, 'B', 1, '不可數 homework 用 How much。'),
('elementary', 'Pick ___ apple from the basket.', '["A. a", "B. an", "C. the", "D. no article"]'::jsonb, 'B', 1, 'apple 母音開頭用 an。'),
('junior', 'If it ___ tomorrow, we will cancel the trip.', '["A. will rain", "B. rains", "C. rained", "D. rain"]'::jsonb, 'B', 1, '第一條件句 if + 現在，主句未來。'),
('junior', 'Unless you hurry, you ___ the train.', '["A. catch", "B. will catch", "C. won''t catch", "D. caught"]'::jsonb, 'C', 2, 'Unless = if not，錯過車用未來否定。'),
('junior', 'By 2030, scientists believe many cars ___ electric.', '["A. are", "B. were", "C. will be", "D. have been"]'::jsonb, 'C', 2, '未來時間用 will be。'),
('junior', 'She ___ since Monday.', '["A. is sick", "B. has been sick", "C. was sick", "D. sicks"]'::jsonb, 'B', 1, 'since + 時間點用現在完成或完成進行；此處 has been sick。'),
('junior', 'I ___ my keys. Have you seen them?', '["A. lost", "B. have lost", "C. had lost", "D. lose"]'::jsonb, 'B', 1, '剛剛丟了影響現在，現在完成。'),
('junior', 'This time yesterday I ___ on a bus.', '["A. sit", "B. was sitting", "C. sat", "D. have sat"]'::jsonb, 'B', 1, '特定過去時刻進行用過去進行。'),
('junior', 'He suggested that she ___ early.', '["A. leave", "B. leaves", "C. left", "D. leaving"]'::jsonb, 'A', 0, 'suggest that + 原形（英式）。'),
('junior', 'It''s vital that everyone ___ quiet.', '["A. remain", "B. remains", "C. remained", "D. remaining"]'::jsonb, 'A', 0, 'vital that + (should) + 原形。'),
('junior', 'The roof ___ in last night''s storm.', '["A. damages", "B. was damaged", "C. damaged", "D. has damaged"]'::jsonb, 'B', 1, '屋頂被損壞，過去被動。'),
('junior', 'The cake ___ by my sister.', '["A. made", "B. was made", "C. makes", "D. making"]'::jsonb, 'B', 1, '蛋糕被製作，被動。'),
('junior', 'She admitted ___ the window.', '["A. break", "B. breaking", "C. to break", "D. broke"]'::jsonb, 'B', 1, 'admit + 動名詞。'),
('junior', 'He avoided ___ her at the party.', '["A. see", "B. seeing", "C. to see", "D. saw"]'::jsonb, 'B', 1, 'avoid + 動名詞。'),
('junior', 'I''m planning ___ abroad next year.', '["A. study", "B. to study", "C. studying", "D. studied"]'::jsonb, 'B', 1, 'plan to + 原形。'),
('junior', 'She''s keen ___ learning Japanese.', '["A. for", "B. on", "C. in", "D. at"]'::jsonb, 'B', 1, 'be keen on + 動名詞。'),
('junior', 'The movie was ___ boring that we left early.', '["A. so", "B. such", "C. very", "D. too"]'::jsonb, 'A', 0, 'so...that 如此…以致。'),
('junior', 'It was ___ a boring movie that we left early.', '["A. so", "B. such", "C. very", "D. much"]'::jsonb, 'B', 1, 'such + a + 形 + 名。'),
('junior', 'No sooner had we arrived ___ it started snowing.', '["A. when", "B. than", "C. before", "D. until"]'::jsonb, 'B', 1, 'No sooner...than 固定。'),
('junior', 'Hardly had he spoken ___ someone interrupted.', '["A. than", "B. when", "C. before", "D. after"]'::jsonb, 'B', 1, 'Hardly...when。'),
('junior', 'Were I you, I ___ accept the offer.', '["A. will", "B. would", "C. can", "D. shall"]'::jsonb, 'B', 1, '虛擬與現在相反用 would。'),
('junior', 'I wish I ___ how to fix this.', '["A. know", "B. knew", "C. have known", "D. knowing"]'::jsonb, 'B', 1, 'wish + 過去式表與現在願望相反。'),
('junior', 'I''d rather you ___ here tonight.', '["A. stay", "B. stayed", "C. staying", "D. to stay"]'::jsonb, 'B', 1, 'would rather + 子句常用過去式表對他人期望。'),
('junior', 'The boy ___ wallet was lost cried.', '["A. who", "B. whom", "C. whose", "D. which"]'::jsonb, 'C', 2, '所有格 whose wallet。'),
('junior', 'This is the factory ___ my uncle works.', '["A. which", "B. where", "C. that", "D. what"]'::jsonb, 'B', 1, '地點先行詞 where。'),
('junior', 'She didn''t tell me ___ she was leaving.', '["A. that", "B. if", "C. what", "D. which"]'::jsonb, 'B', 1, '是否離開用 if/whether。'),
('junior', '___ breaks the law must face consequences.', '["A. Whoever", "B. Who", "C. Whomever", "D. Whatever"]'::jsonb, 'A', 0, '無論誰 whoever。'),
('junior', 'However hard he tried, he ___ pass.', '["A. can''t", "B. couldn''t", "C. doesn''t", "D. won''t"]'::jsonb, 'B', 1, 'However hard，過去嘗試用 couldn''t。'),
('junior', 'The news ___ quite shocking.', '["A. are", "B. were", "C. was", "D. be"]'::jsonb, 'C', 2, 'news 不可數單數。'),
('junior', 'Physics ___ my weakest subject.', '["A. are", "B. were", "C. is", "D. be"]'::jsonb, 'C', 2, '學科 physics 單數。'),
('junior', 'Either Tom or his cousins ___ coming.', '["A. is", "B. are", "C. was", "D. be"]'::jsonb, 'B', 1, 'either or 動詞與較近主詞一致。'),
('junior', 'Not only the coach but also the players ___ happy.', '["A. was", "B. were", "C. is", "D. be"]'::jsonb, 'B', 1, 'but also 後 players 複數。'),
('junior', 'She speaks ___ she had rehearsed for hours.', '["A. even if", "B. as if", "C. unless", "D. until"]'::jsonb, 'B', 1, '好像 as if。'),
('junior', 'The building ___ next year.', '["A. completes", "B. will complete", "C. will be completed", "D. completed"]'::jsonb, 'C', 2, '明年被完工，未來被動。'),
('junior', 'I remember ___ the door before bed.', '["A. lock", "B. to lock", "C. locking", "D. locked"]'::jsonb, 'C', 2, '記得做過 locking。'),
('junior', 'Please remember ___ the door before you leave.', '["A. lock", "B. to lock", "C. locking", "D. locked"]'::jsonb, 'B', 1, '記得要去做的尚未做，to lock。'),
('junior', 'He is used ___ early for his job.', '["A. to get up", "B. to getting up", "C. get up", "D. getting up"]'::jsonb, 'B', 1, 'be used to + 動名詞表習慣。'),
('junior', 'He used ___ early before retirement.', '["A. to get up", "B. to getting up", "C. get up", "D. getting up"]'::jsonb, 'A', 0, 'used to + 原形表過去習慣。'),
('junior', 'She got her brother ___ the heavy box.', '["A. carry", "B. to carry", "C. carrying", "D. carried"]'::jsonb, 'B', 1, 'get + 人 + to + 原形。'),
('junior', 'We had the roof ___ after the storm.', '["A. repair", "B. repaired", "C. repairing", "D. repairs"]'::jsonb, 'B', 1, 'have + 物 + 過去分詞。'),
('junior', 'The problem ___ at yesterday''s meeting.', '["A. discusses", "B. was discussed", "C. discussed", "D. is discussing"]'::jsonb, 'B', 1, '問題被討論。'),
('junior', '___ careful when you cross the street.', '["A. Be", "B. Being", "C. To be", "D. Been"]'::jsonb, 'A', 0, '祈使句 Be careful。'),
('junior', 'Reading: Tim forgot his keys and missed the bus. Why might Tim be late?', '["A. He woke early", "B. He couldn''t enter his house fast", "C. He loves buses", "D. He ran fast"]'::jsonb, 'B', 1, '忘記鑰匙可能耽誤出門。'),
('junior', 'Reading: The café opens at 7 a.m. Does it open before 8?', '["A. No", "B. Yes", "C. Only on Sundays", "D. Unknown"]'::jsonb, 'B', 1, '七點開門，八點前已開。'),
('junior', 'Choose the closest meaning to ''generous''.', '["A. greedy", "B. kind and giving", "C. shy", "D. strict"]'::jsonb, 'B', 1, 'generous 表示慷慨。'),
('junior', 'Choose the closest meaning to ''ancient''.', '["A. modern", "B. very old", "C. tiny", "D. noisy"]'::jsonb, 'B', 1, 'ancient 古老。'),
('junior', 'She has ___ experience than I do.', '["A. much", "B. more", "C. most", "D. many"]'::jsonb, 'B', 1, 'than 比較 more experience。'),
('junior', 'This is ___ difficult exam I''ve taken.', '["A. more", "B. most", "C. the most", "D. much"]'::jsonb, 'C', 2, '最高級 the most difficult。'),
('junior', 'He speaks Spanish ___ than I do.', '["A. fluent", "B. more fluently", "C. most fluent", "D. fluently"]'::jsonb, 'B', 1, '修飾動詞 speaks 用副詞比較。'),
('junior', 'I''d ___ stay home than go out in this rain.', '["A. rather", "B. prefer", "C. better", "D. want"]'::jsonb, 'A', 0, 'would rather...than。'),
('junior', 'She''d prefer ___ alone tonight.', '["A. be", "B. to be", "C. being", "D. been"]'::jsonb, 'B', 1, 'would prefer to be。'),
('junior', 'It''s worth ___ the instructions twice.', '["A. read", "B. reading", "C. to read", "D. reads"]'::jsonb, 'B', 1, 'worth + 動名詞。'),
('junior', 'There''s no point in ___ over failed exams.', '["A. worry", "B. worrying", "C. to worry", "D. worried"]'::jsonb, 'B', 1, 'no point in + 動名詞。'),
('junior', 'She prevented him ___ entering the room.', '["A. from", "B. to", "C. for", "D. of"]'::jsonb, 'A', 0, 'prevent from + 動名詞。'),
('junior', 'The rain stopped them ___ playing tennis.', '["A. from", "B. to", "C. of", "D. for"]'::jsonb, 'A', 0, 'stop from + 動名詞。'),
('junior', 'He congratulated me ___ winning.', '["A. for", "B. on", "C. with", "D. about"]'::jsonb, 'B', 1, 'congratulate on + 動名詞。'),
('junior', 'She apologized ___ being rude.', '["A. for", "B. to", "C. of", "D. about"]'::jsonb, 'A', 0, 'apologize for + 動名詞。'),
('junior', 'I''m responsible ___ the schedule.', '["A. for", "B. of", "C. to", "D. with"]'::jsonb, 'A', 0, 'responsible for。'),
('junior', 'He''s addicted ___ online games.', '["A. for", "B. to", "C. on", "D. with"]'::jsonb, 'B', 1, 'addicted to。'),
('junior', 'The teacher explained the rule ___ .', '["A. clear", "B. clearly", "C. clearness", "D. clearer"]'::jsonb, 'B', 1, '修飾動詞 explained 用副詞。'),
('junior', 'She looked ___ when she heard the news.', '["A. surprising", "B. surprised", "C. surprise", "D. surprisingly"]'::jsonb, 'B', 1, '形容人用 surprised。'),
('junior', 'The lecture was ___ tedious that several listeners left early.', '["A. so", "B. such", "C. very", "D. too"]'::jsonb, 'A', 0, 'so...that 如此…以致；tedious 形前用 so。'),
('junior', 'Seldom ___ such a crowd here.', '["A. we saw", "B. did we see", "C. we see", "D. have we seen"]'::jsonb, 'B', 1, 'Seldom 開頭倒裝。'),
